package il.co.dcd.composermapper.model; import java.nio.file.Path; import java.util.*;
public class FormatDef { private String id; private Path sourceFile; private TagNode rootTag; private final Set<String> referencedXmlTags=new LinkedHashSet<>(); private final Set<String> referencedMappedJavaClasses=new LinkedHashSet<>(); private final Set<String> inferredExternalDependencies=new LinkedHashSet<>(); public String getId(){return id;} public void setId(String id){this.id=id;} public Path getSourceFile(){return sourceFile;} public void setSourceFile(Path p){this.sourceFile=p;} public TagNode getRootTag(){return rootTag;} public void setRootTag(TagNode t){this.rootTag=t;} public Set<String> getReferencedXmlTags(){return referencedXmlTags;} public Set<String> getReferencedMappedJavaClasses(){return referencedMappedJavaClasses;} public Set<String> getInferredExternalDependencies(){return inferredExternalDependencies;} }
